## TabBar Component

The `TabBar` component is a React functional component responsible for rendering a tab navigation interface. It allows users to switch between different tabs, close individual tabs, and add new ones.

### Purpose

This component provides a user-friendly way to manage multiple views or documents within a single application window, mimicking the behavior of browser tabs.

### Key Exports

*   **`TabBar`**: The main React component.

### Props

*   **`tabs`** (`Tab[]`): An array of `Tab` objects, where each `Tab` object should have at least `id` (string) and `label` (string) properties. This prop defines the available tabs to be displayed.
*   **`activeTabId`** (`string`): The ID of the currently active tab. This prop is used to style the active tab and determine its visual state.
*   **`onSwitch`** (`(id: string) => void`): A callback function that is invoked when a tab is clicked to switch to it. It receives the `id` of the clicked tab.
*   **`onClose`** (`(id: string) => void`): A callback function that is invoked when the close button of a tab is clicked. It receives the `id` of the tab to be closed.
*   **`onAdd`** (`() => void`): A callback function that is invoked when the 'add new tab' button is clicked.

### Usage Example

```jsx
import React, { useState } from 'react';
import { TabBar } from './TabBar'; // Assuming TabBar.tsx is in the same directory
import type { Tab } from './types'; // Assuming types.ts defines the Tab interface

const App: React.FC = () => {
  const [tabs, setTabs] = useState<Tab[]>([
    { id: 'tab1', label: 'Welcome' },
    { id: 'tab2', label: 'Settings' },
  ]);
  const [activeTabId, setActiveTabId] = useState<string>('tab1');

  const handleSwitchTab = (id: string) => {
    setActiveTabId(id);
  };

  const handleCloseTab = (id: string) => {
    setTabs(tabs.filter(tab => tab.id !== id));
    // If the closed tab was active, switch to another tab
    if (activeTabId === id && tabs.length > 1) {
      setActiveTabId(tabs.find(tab => tab.id !== id)!.id);
    } else if (tabs.length === 1) {
      // Handle case where the last tab is closed, maybe open a default one
      setTabs([{ id: 'new-default', label: 'New Tab' }]);
      setActiveTabId('new-default');
    }
  };

  const handleAddTab = () => {
    const newTabId = `tab${tabs.length + 1}`;
    const newTab: Tab = { id: newTabId, label: `Tab ${tabs.length + 1}` };
    setTabs([...tabs, newTab]);
    setActiveTabId(newTabId);
  };

  return (
    <div>
      <TabBar
        tabs={tabs}
        activeTabId={activeTabId}
        onSwitch={handleSwitchTab}
        onClose={handleCloseTab}
        onAdd={handleAddTab}
      />
      {/* Render content based on activeTabId */}
      <div>
        {activeTabId === 'tab1' && <div>Content for Welcome Tab</div>}
        {activeTabId === 'tab2' && <div>Content for Settings Tab</div>}
        {/* ... other tab content */}
      </div>
    </div>
  );
};

export default App;
```
